import heapq
import collections

class Task:
    def __init__(self, id, arrival_time, burst_time):
        self.id = id
        self.arrival_time = arrival_time
        self.burst_time = burst_time
        self.remaining_time = burst_time

    def __lt__(self, other):
        if self.remaining_time != other.remaining_time:
            return self.remaining_time < other.remaining_time
        if self.arrival_time != other.arrival_time:
            return self.arrival_time < other.arrival_time
        return self.id < other.id

def simulate_cpu_with_heap(task_data):
    all_tasks = [Task(t[0], t[1], t[2]) for t in task_data]
    all_tasks.sort(key=lambda x: x.arrival_time)

    current_time = 0
    ready_queue = []

    tasks_not_arrived = collections.deque(all_tasks)

    current_running_task = None
    timeline = []

    finished_tasks_count = 0

    while finished_tasks_count < len(all_tasks) or current_running_task is not None or len(ready_queue) > 0 or len(tasks_not_arrived) > 0:

        while tasks_not_arrived and tasks_not_arrived[0].arrival_time <= current_time:
            task_to_add = tasks_not_arrived.popleft()
            heapq.heappush(ready_queue, task_to_add)

        if current_running_task is not None:
            if ready_queue and ready_queue[0].remaining_time < current_running_task.remaining_time:
                heapq.heappush(ready_queue, current_running_task)
                current_running_task = None

        if current_running_task is None and ready_queue:
            current_running_task = heapq.heappop(ready_queue)

        if current_running_task:
            current_running_task.remaining_time -= 1
            timeline.append(f"T{current_running_task.id}")

            if current_running_task.remaining_time == 0:
                finished_tasks_count += 1
                current_running_task = None
        else:
            timeline.append("IDLE")

        current_time += 1

    return timeline
